-- Cloudflare D1 SQL: legal_actions table
CREATE TABLE IF NOT EXISTS legal_actions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  court_type TEXT NOT NULL,
  stage TEXT NOT NULL,
  action_name TEXT NOT NULL,
  responsible TEXT,
  deadline TEXT,
  deadline_from TEXT,
  legal_source TEXT,
  practical_notes TEXT
);

CREATE TABLE IF NOT EXISTS case_suggested_actions (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  client_id TEXT NOT NULL,
  case_id TEXT NOT NULL,
  document_name TEXT,
  court_type TEXT,
  suggested_action TEXT,
  deadline TEXT,
  legal_source TEXT,
  confidence TEXT,
  reasoning TEXT,
  created_at DATETIME DEFAULT CURRENT_TIMESTAMP
);

